#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M, K;
        scanf("%d %d %d", &N, &M, &K);
        if (N + K <= M) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

